toolArgs.file_text:
@page "/apply"
@rendermode InteractiveServer
@using sv_2c831dde22b04c74ac1de04f6b83e39f.Models
@using sv_2c831dde22b04c74ac1de04f6b83e39f.Services
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="container py-4">
    <h2 class="mb-4">Job Application</h2>

    @* ───── Step Indicator Bar ───── *@
    <div class="step-indicator mb-4">
        @for (int i = 0; i < _stepNames.Length; i++)
        {
            var stepIndex = i;
            var state = GetStepState(stepIndex);
            <div class="step-item @state" @onclick="() => OnStepClick(stepIndex)">
                <div class="step-circle">
                    @if (state == "completed")
                    {
                        <span>&#10003;</span>
                    }
                    else
                    {
                        <span>@(stepIndex + 1)</span>
                    }
                </div>
                <div class="step-label">@_stepNames[stepIndex]</div>
            </div>
            @if (stepIndex < _stepNames.Length - 1)
            {
                <div class="step-connector @(stepIndex < _currentStep ? "completed" : "")"></div>
            }
        }
    </div>

    @if (!string.IsNullOrEmpty(_errorMessage))
    {
        <div class="alert alert-danger">@_errorMessage</div>
    }

    @* ───── Step 1: Personal Info ───── *@
    @if (_currentStep == 0)
    {
        <div class="card">
            <div class="card-header"><h5 class="mb-0">Personal Information</h5></div>
            <div class="card-body">
                <div class="mb-3">
                    <label class="form-label">Full Name <span class="text-danger">*</span></label>
                    <input class="form-control" @bind="_fullName" placeholder="Enter your full name" />
                </div>
                <div class="mb-3">
                    <label class="form-label">Email <span class="text-danger">*</span></label>
                    <input type="email" class="form-control" @bind="_email" placeholder="you@example.com" />
                    @if (!string.IsNullOrEmpty(_emailError))
                    {
                        <div class="text-danger mt-1">@_emailError</div>
                    }
                </div>
                <div class="mb-3">
                    <label class="form-label">Phone <span class="text-danger">*</span></label>
                    <input type="tel" class="form-control" @bind="_phone" placeholder="(555) 123-4567" />
                </div>
                <div class="mb-3">
                    <label class="form-label">Address <span class="text-danger">*</span></label>
                    <textarea class="form-control" rows="2" @bind="_address" placeholder="Street, City, State, ZIP"></textarea>
                </div>
                <div class="d-flex justify-content-end">
                    <button class="btn btn-primary" @onclick="NextStep" disabled="@_isValidating">
                        @if (_isValidating)
                        {
                            <span class="spinner-border spinner-border-sm me-1"></span>
                        }
                        Next
                    </button>
                </div>
            </div>
        </div>
    }

    @* ───── Step 2: Work History ───── *@
    @if (_currentStep == 1)
    {
        <div class="card">
            <div class="card-header"><h5 class="mb-0">Work History</h5></div>
            <div class="card-body">
                @for (int i = 0; i < _workEntries.Count; i++)
                {
                    var idx = i;
                    <div class="border rounded p-3 mb-3 position-relative">
                        <h6>Position @(idx + 1)</h6>
                        @if (_workEntries.Count > 1)
                        {
                            <button class="btn btn-sm btn-outline-danger position-absolute top-0 end-0 m-2"
                                    @onclick="() => RemoveWorkEntry(idx)">Remove</button>
                        }
                        <div class="row">
                            <div class="col-md-6 mb-3">
                                <label class="form-label">Company <span class="text-danger">*</span></label>
                                <input class="form-control" @bind="_workEntries[idx].Company" />
                            </div>
                            <div class="col-md-6 mb-3">
                                <label class="form-label">Job Title <span class="text-danger">*</span></label>
                                <input class="form-control" @bind="_workEntries[idx].Title" />
                            </div>
                        </div>
                        <div class="row">
                            <div class="col-md-4 mb-3">
                                <label class="form-label">Start Date <span class="text-danger">*</span></label>
                                <input type="date" class="form-control" @bind="_workEntries[idx].StartDate" />
                            </div>
                            <div class="col-md-4 mb-3">
                                <label class="form-label">End Date</label>
                                <input type="date" class="form-control" @bind="_workEntries[idx].EndDate"
                                       disabled="@_workEntries[idx].IsCurrent" />
                            </div>
                            <div class="col-md-4 mb-3 d-flex align-items-end">
                                <div class="form-check">
                                    <input class="form-check-input" type="checkbox" id="current-@idx"
                                           @bind="_workEntries[idx].IsCurrent" />
                                    <label class="form-check-label" for="current-@idx">Currently working here</label>
                                </div>
                            </div>
                        </div>
                        <div class="mb-3">
                            <label class="form-label">Description <span class="text-danger">*</span></label>
                            <textarea class="form-control" rows="2" @bind="_workEntries[idx].Description"></textarea>
                        </div>
                    </div>
                }
                <button class="btn btn-outline-secondary mb-3" @onclick="AddWorkEntry">
                    + Add Another Position
                </button>
                <div class="d-flex justify-content-between">
                    <button class="btn btn-secondary" @onclick="PreviousStep">Back</button>
                    <button class="btn btn-primary" @onclick="NextStep">Next</button>
                </div>
            </div>
        </div>
    }

    @* ───── Step 3: References ───── *@
    @if (_currentStep == 2)
    {
        <div class="card">
            <div class="card-header"><h5 class="mb-0">References</h5></div>
            <div class="card-body">
                @for (int i = 0; i < _references.Count; i++)
                {
                    var idx = i;
                    <div class="border rounded p-3 mb-3 position-relative">
                        <h6>Reference @(idx + 1)</h6>
                        @if (_references.Count > 2)
                        {
                            <button class="btn btn-sm btn-outline-danger position-absolute top-0 end-0 m-2"
                                    @onclick="() => RemoveReference(idx)">Remove</button>
                        }
                        <div class="row">
                            <div class="col-md-6 mb-3">
                                <label class="form-label">Name <span class="text-danger">*</span></label>
                                <input class="form-control" @bind="_references[idx].Name" />
                            </div>
                            <div class="col-md-6 mb-3">
                                <label class="form-label">Relationship <span class="text-danger">*</span></label>
                                <input class="form-control" @bind="_references[idx].Relationship" />
                            </div>
                        </div>
                        <div class="row">
                            <div class="col-md-6 mb-3">
                                <label class="form-label">Email <span class="text-danger">*</span></label>
                                <input type="email" class="form-control" @bind="_references[idx].Email" />
                            </div>
                            <div class="col-md-6 mb-3">
                                <label class="form-label">Phone <span class="text-danger">*</span></label>
                                <input type="tel" class="form-control" @bind="_references[idx].Phone" />
                            </div>
                        </div>
                    </div>
                }
                @if (_references.Count < 3)
                {
                    <button class="btn btn-outline-secondary mb-3" @onclick="AddReference">
                        + Add Reference
                    </button>
                }
                <div class="d-flex justify-content-between">
                    <button class="btn btn-secondary" @onclick="PreviousStep">Back</button>
                    <button class="btn btn-primary" @onclick="NextStep">Next</button>
                </div>
            </div>
        </div>
    }

    @* ───── Step 4: Cover Letter ───── *@
    @if (_currentStep == 3)
    {
        <div class="card">
            <div class="card-header"><h5 class="mb-0">Cover Letter</h5></div>
            <div class="card-body">
                <div class="mb-3">
                    <label class="form-label">Write your cover letter <span class="text-danger">*</span></label>
                    <textarea class="form-control" rows="10" maxlength="@CoverLetterMaxLength"
                              @bind="_coverLetter" @bind:event="oninput"
                              placeholder="Tell us why you'd be a great fit…"></textarea>
                    <div class="text-muted mt-1 text-end">
                        @(_coverLetter?.Length ?? 0) / @CoverLetterMaxLength characters
                    </div>
                </div>
                <div class="d-flex justify-content-between">
                    <button class="btn btn-secondary" @onclick="PreviousStep">Back</button>
                    <button class="btn btn-primary" @onclick="NextStep">Next</button>
                </div>
            </div>
        </div>
    }

    @* ───── Step 5: Review & Submit ───── *@
    @if (_currentStep == 4)
    {
        @if (_submitted)
        {
            <div class="card border-success">
                <div class="card-body text-center py-5">
                    <h3 class="text-success mb-3">&#10003; Application Submitted!</h3>
                    <p class="lead">Your application has been received.</p>
                    <p>Application ID: <strong>@_applicationId</strong></p>
                </div>
            </div>
        }
        else
        {
            <div class="card">
                <div class="card-header"><h5 class="mb-0">Review & Submit</h5></div>
                <div class="card-body">

                    @* Personal Info *@
                    <div class="mb-4">
                        <div class="d-flex justify-content-between align-items-center mb-2">
                            <h6 class="mb-0">Personal Information</h6>
                            <button class="btn btn-sm btn-link" @onclick='() => GoToStep(0)'>Edit</button>
                        </div>
                        <table class="table table-sm mb-0">
                            <tr><th style="width:150px">Name</th><td>@_fullName</td></tr>
                            <tr><th>Email</th><td>@_email</td></tr>
                            <tr><th>Phone</th><td>@_phone</td></tr>
                            <tr><th>Address</th><td>@_address</td></tr>
                        </table>
                    </div>

                    @* Work History *@
                    <div class="mb-4">
                        <div class="d-flex justify-content-between align-items-center mb-2">
                            <h6 class="mb-0">Work History</h6>
                            <button class="btn btn-sm btn-link" @onclick='() => GoToStep(1)'>Edit</button>
                        </div>
                        @foreach (var entry in _workEntries)
                        {
                            <div class="border rounded p-2 mb-2">
                                <strong>@entry.Title</strong> at @entry.Company<br />
                                <small class="text-muted">
                                    @entry.StartDate.ToString("MMM yyyy") –
                                    @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy"))
                                </small>
                                <p class="mb-0 mt-1">@entry.Description</p>
                            </div>
                        }
                    </div>

                    @* References *@
                    <div class="mb-4">
                        <div class="d-flex justify-content-between align-items-center mb-2">
                            <h6 class="mb-0">References</h6>
                            <button class="btn btn-sm btn-link" @onclick='() => GoToStep(2)'>Edit</button>
                        </div>
                        @foreach (var r in _references)
                        {
                            <div class="border rounded p-2 mb-2">
                                <strong>@r.Name</strong> — @r.Relationship<br />
                                <small class="text-muted">@r.Email | @r.Phone</small>
                            </div>
                        }
                    </div>

                    @* Cover Letter *@
                    <div class="mb-4">
                        <div class="d-flex justify-content-between align-items-center mb-2">
                            <h6 class="mb-0">Cover Letter</h6>
                            <button class="btn btn-sm btn-link" @onclick='() => GoToStep(3)'>Edit</button>
                        </div>
                        <div class="border rounded p-3 bg-light" style="white-space:pre-wrap">@_coverLetter</div>
                    </div>

                    <div class="d-flex justify-content-between">
                        <button class="btn btn-secondary" @onclick="PreviousStep">Back</button>
                        <button class="btn btn-success btn-lg" @onclick="SubmitApplication" disabled="@_isSubmitting">
                            @if (_isSubmitting)
                            {
                                <span class="spinner-border spinner-border-sm me-1"></span>
                            }
                            Submit Application
                        </button>
                    </div>
                </div>
            </div>
        }
    }
</div>

@code {
    private const int CoverLetterMaxLength = 2000;

    private static readonly string[] _stepNames =
        ["Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"];

    private int _currentStep;
    private bool _isValidating;
    private bool _isSubmitting;
    private bool _submitted;
    private int _applicationId;
    private string? _errorMessage;
    private string? _emailError;

    // Step 1
    private string _fullName = "";
    private string _email = "";
    private string _phone = "";
    private string _address = "";

    // Step 2
    private List<WorkEntryModel> _workEntries = [new()];

    // Step 3
    private List<ReferenceModel> _references = [new(), new()];

    // Step 4
    private string _coverLetter = "";

    private string GetStepState(int step)
    {
        if (step == _currentStep) return "active";
        if (step < _currentStep) return "completed";
        return "dimmed";
    }

    private void OnStepClick(int step)
    {
        if (step < _currentStep)
            GoToStep(step);
    }

    private void GoToStep(int step)
    {
        _errorMessage = null;
        _emailError = null;
        _currentStep = step;
    }

    private void PreviousStep()
    {
        _errorMessage = null;
        _emailError = null;
        if (_currentStep > 0) _currentStep--;
    }

    private async Task NextStep()
    {
        _errorMessage = null;
        _emailError = null;

        if (!ValidateCurrentStep())
            return;

        if (_currentStep == 0)
        {
            _isValidating = true;
            try
            {
                var valid = await ApplicationService.ValidateEmailAsync(_email);
                if (!valid)
                {
                    _emailError = "Please enter a valid email address.";
                    return;
                }
            }
            finally
            {
                _isValidating = false;
            }
        }

        _currentStep++;
    }

    private bool ValidateCurrentStep()
    {
        switch (_currentStep)
        {
            case 0:
                if (string.IsNullOrWhiteSpace(_fullName) || string.IsNullOrWhiteSpace(_email) ||
                    string.IsNullOrWhiteSpace(_phone) || string.IsNullOrWhiteSpace(_address))
                {
                    _errorMessage = "All personal information fields are required.";
                    return false;
                }
                break;

            case 1:
                foreach (var entry in _workEntries)
                {
                    if (string.IsNullOrWhiteSpace(entry.Company) || string.IsNullOrWhiteSpace(entry.Title) ||
                        string.IsNullOrWhiteSpace(entry.Description) || entry.StartDate == default)
                    {
                        _errorMessage = "Please complete all required fields for each work entry.";
                        return false;
                    }
                }
                break;

            case 2:
                foreach (var r in _references)
                {
                    if (string.IsNullOrWhiteSpace(r.Name) || string.IsNullOrWhiteSpace(r.Relationship) ||
                        string.IsNullOrWhiteSpace(r.Email) || string.IsNullOrWhiteSpace(r.Phone))
                    {
                        _errorMessage = "Please complete all required fields for each reference.";
                        return false;
                    }
                }
                break;

            case 3:
                if (string.IsNullOrWhiteSpace(_coverLetter))
                {
                    _errorMessage = "Cover letter is required.";
                    return false;
                }
                break;
        }
        return true;
    }

    private async Task SubmitApplication()
    {
        _isSubmitting = true;
        _errorMessage = null;
        try
        {
            var personal = new PersonalInfo(_fullName, _email, _phone, _address);
            var workHistory = new WorkHistory(
                _workEntries.Select(e => new WorkEntry(
                    e.Company, e.Title, e.StartDate, e.IsCurrent ? null : e.EndDate, e.Description)).ToList());
            var references = _references.Select(r => new Reference(r.Name, r.Relationship, r.Email, r.Phone)).ToList();
            var application = new JobApplication(personal, workHistory, references, _coverLetter);

            _applicationId = await ApplicationService.SubmitApplicationAsync(application);
            _submitted = true;
        }
        catch (Exception ex)
        {
            _errorMessage = $"Submission failed: {ex.Message}";
        }
        finally
        {
            _isSubmitting = false;
        }
    }

    // Mutable helper models for form binding
    private void AddWorkEntry() => _workEntries.Add(new());
    private void RemoveWorkEntry(int index) => _workEntries.RemoveAt(index);
    private void AddReference() { if (_references.Count < 3) _references.Add(new()); }
    private void RemoveReference(int index) => _references.RemoveAt(index);

    private class WorkEntryModel
    {
        public string Company { get; set; } = "";
        public string Title { get; set; } = "";
        public DateTime StartDate { get; set; }
        public DateTime? EndDate { get; set; }
        public bool IsCurrent { get; set; }
        public string Description { get; set; } = "";
    }

    private class ReferenceModel
    {
        public string Name { get; set; } = "";
        public string Relationship { get; set; } = "";
        public string Email { get; set; } = "";
        public string Phone { get; set; } = "";
    }
}

